import { useMemo, useState } from "react";
import "./App.css";

// Predefined delivery locations (sample coordinates)
const LOCATIONS = [
  { id: 0, name: "Depot", lat: 28.6139, lng: 77.209 },
  { id: 1, name: "Point A", lat: 28.7041, lng: 77.1025 },
  { id: 2, name: "Point B", lat: 28.5355, lng: 77.391 },
  { id: 3, name: "Point C", lat: 28.4595, lng: 77.0266 },
  { id: 4, name: "Point D", lat: 28.4089, lng: 77.3178 },
  { id: 5, name: "Point E", lat: 28.6692, lng: 77.4538 },
  { id: 6, name: "Point F", lat: 28.9845, lng: 77.7064 },
];

// Haversine distance in km
function haversineKm(a, b) {
  const R = 6371;
  const toRad = (deg) => (deg * Math.PI) / 180;
  const dLat = toRad(b.lat - a.lat);
  const dLng = toRad(b.lng - a.lng);

  const x =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(a.lat)) * Math.cos(toRad(b.lat)) * Math.sin(dLng / 2) ** 2;

  return 2 * R * Math.asin(Math.sqrt(x));
}

function buildDistanceMatrix(points) {
  const n = points.length;
  const m = Array.from({ length: n }, () => Array(n).fill(0));
  for (let i = 0; i < n; i++) {
    for (let j = i + 1; j < n; j++) {
      const d = haversineKm(points[i], points[j]);
      m[i][j] = d;
      m[j][i] = d;
    }
  }
  return m;
}

function routeDistance(route, matrix) {
  let total = 0;
  for (let i = 0; i < route.length - 1; i++) {
    total += matrix[route[i]][route[i + 1]];
  }
  return total;
}

// Nearest Neighbor initial route (cycle: start -> ... -> start)
function nearestNeighbor(points, matrix, startIndex) {
  const n = points.length;
  const unvisited = new Set(Array.from({ length: n }, (_, i) => i));
  unvisited.delete(startIndex);

  const route = [startIndex];
  let current = startIndex;

  while (unvisited.size > 0) {
    let best = null;
    let bestD = Infinity;
    for (const cand of unvisited) {
      const d = matrix[current][cand];
      if (d < bestD) {
        bestD = d;
        best = cand;
      }
    }
    route.push(best);
    unvisited.delete(best);
    current = best;
  }

  route.push(startIndex); // close cycle
  return route;
}

// 2-opt optimization
function twoOpt(initialRoute, matrix, maxPasses = 100) {
  let route = [...initialRoute];
  let improved = true;
  let pass = 0;

  // Keep first and last fixed (same depot)
  while (improved && pass < maxPasses) {
    improved = false;
    pass++;

    for (let i = 1; i < route.length - 2; i++) {
      for (let k = i + 1; k < route.length - 1; k++) {
        const a = route[i - 1];
        const b = route[i];
        const c = route[k];
        const d = route[k + 1];

        const current = matrix[a][b] + matrix[c][d];
        const swapped = matrix[a][c] + matrix[b][d];

        if (swapped + 1e-9 < current) {
          // reverse segment i..k
          const reversed = route.slice(i, k + 1).reverse();
          route = [...route.slice(0, i), ...reversed, ...route.slice(k + 1)];
          improved = true;
        }
      }
    }
  }

  return route;
}

function App() {
  const [startId, setStartId] = useState(0);

  const result = useMemo(() => {
    const points = LOCATIONS;
    const matrix = buildDistanceMatrix(points);

    const nnRoute = nearestNeighbor(points, matrix, startId);
    const nnDistance = routeDistance(nnRoute, matrix);

    const optRoute = twoOpt(nnRoute, matrix, 80);
    const optDistance = routeDistance(optRoute, matrix);

    const toNames = (route) => route.map((idx) => points[idx].name);

    return {
      nnRoute,
      nnDistance,
      optRoute,
      optDistance,
      improvement: nnDistance - optDistance,
      improvementPct:
        nnDistance > 0 ? ((nnDistance - optDistance) / nnDistance) * 100 : 0,
      nnNames: toNames(nnRoute),
      optNames: toNames(optRoute),
    };
  }, [startId]);

  return (
    <div className="container">
      <h1>Delivery Route Optimizer</h1>
      <p className="subtitle">
        Minimizes total distance across predefined delivery locations using
        Nearest Neighbor + 2-opt.
      </p>

      <section className="card">
        <h2>Settings</h2>
        <label htmlFor="depot">Depot / Start location:</label>
        <select
          id="depot"
          value={startId}
          onChange={(e) => setStartId(Number(e.target.value))}
        >
          {LOCATIONS.map((p) => (
            <option key={p.id} value={p.id}>
              {p.name}
            </option>
          ))}
        </select>
      </section>

      <section className="card">
        <h2>Distance Results</h2>
        <div className="metrics">
          <div>
            <strong>Initial (Nearest Neighbor):</strong>{" "}
            {result.nnDistance.toFixed(2)} km
          </div>
          <div>
            <strong>Optimized (2-opt):</strong> {result.optDistance.toFixed(2)}{" "}
            km
          </div>
          <div>
            <strong>Distance Saved:</strong> {result.improvement.toFixed(2)} km
          </div>
          <div>
            <strong>Improvement:</strong> {result.improvementPct.toFixed(2)}%
          </div>
        </div>
      </section>

      <section className="card">
        <h2>Initial Route</h2>
        <p>{result.nnNames.join(" -> ")}</p>
      </section>

      <section className="card">
        <h2>Optimized Route</h2>
        <p>{result.optNames.join(" -> ")}</p>
      </section>

      <section className="card">
        <h2>Why this approach?</h2>
        <ul>
          <li>Exact TSP search is expensive for larger location sets.</li>
          <li>Nearest Neighbor gives a fast baseline route.</li>
          <li>2-opt removes inefficient edge crossings and shortens distance.</li>
          <li>Good quality results with low browser-side computation cost.</li>
        </ul>
      </section>
    </div>
  );
}

export default App;
